  {"id":89,"type":"number","question":"Wie viele Blöcke kann ein Kolben (Piston) in einer Linie schieben?","answer":12,"unit":"Blöcke","tolerance":0,"category":"Redstone","funFact":"Ein Kolben kann maximal 12 Blöcke schieben. Mit Schleimblöcken können Strukturen als Einheit bewegt werden."},
  {"id":90,"type":"number","question":"Wie viele Redstone-Ticks dauert ein Repeater auf maximaler Verzögerung?","answer":4,"unit":"Redstone-Ticks","tolerance":0,"category":"Redstone","funFact":"Ein Redstone-Tick = 2 Game-Ticks = 0,1 Sekunden. Ein Repeater auf Stufe 4 verzögert das Signal um 0,4 Sekunden."},
  {"id":91,"type":"number","question":"Wie viele Slots hat ein Trichter (Hopper)?","answer":5,"unit":"Slots","tolerance":0,"category":"Redstone","funFact":"Trichter transportieren Items mit 2,5 Items pro Sekunde. Sie können nach unten oder seitwärts gerichtet werden."},
  {"id":92,"type":"number","question":"Wie hoch ist die maximale Build Height in Minecraft (Y-Level)?","answer":320,"unit":"Y-Level","tolerance":0,"category":"Weltgenerierung","funFact":"Build Height: Y=320. Wolken befinden sich bei Y=192. Vor 1.18 war die maximale Höhe Y=255."},
  {"id":93,"type":"number","question":"Wie viele Meeresschuppen braucht man für einen Schildkröten-Helm?","answer":5,"unit":"Meeresschuppen","tolerance":0,"category":"Crafting","funFact":"Der Schildkröten-Helm gibt 2 Rüstungspunkte und +10 Sekunden Wasseratmung."},
  {"id":94,"type":"entity","question":"Was droppen Baby-Schildkröten, wenn sie erwachsen werden?","answer":"Meeresschuppe","acceptedAnswers":["Meeresschuppe","Scute","Turtle Scute"],"category":"Mobs","funFact":"5 Meeresschuppen = 1 Schildkröten-Helm. Er gibt Konduit-Effekt wenn im Wasser."},
  {"id":95,"type":"number","question":"Wie viele Goldbarren braucht man für einen normalen Goldenen Apfel?","answer":8,"unit":"Goldbarren","tolerance":0,"category":"Crafting","funFact":"8 Goldbarren + 1 Apfel = Goldener Apfel. Der verzauberte (Notch-Apfel) ist nicht mehr herstellbar."},
  {"id":96,"type":"number","question":"Wie viele Goldblöcke brauchte man früher für einen verzauberten Goldenen Apfel (Notch Apple)?","answer":8,"unit":"Goldblöcke","tolerance":0,"category":"Crafting","funFact":"8 Goldblöcke (72 Goldbarren!) + 1 Apfel = Notch-Apfel. Seit 1.9 ist das Rezept entfernt."},
  {"id":97,"type":"entity","question":"Welcher Mob wird durch einen Blitz in ein Zombie Piglin verwandelt?","answer":"Schwein","acceptedAnswers":["Schwein","Pig"],"category":"Mobs","funFact":"Blitzeinschläge verwandeln Schweine in Zombie Piglins, Dorfbewohner in Hexen und Creeper in geladene Creeper."},
