  {"id":120,"type":"number","question":"Wie viel Schaden macht ein Magma Block pro Sekunde beim Draufstehen (halbe Herzen)?","answer":1,"unit":"Schaden/s","tolerance":0,"category":"Blöcke","funFact":"Magmablöcke schaden 1 HP alle 0,5 Sek. Schleichen auf Magmablöcken verhindert den Schaden."},
  {"id":121,"type":"entity","question":"Welcher Block bildet den Boden des End und kann nicht durch Explosionen zerstört werden?","answer":"Endstein","acceptedAnswers":["Endstein","End Stone","Endstone"],"category":"Blöcke","funFact":"Endstein ist der Haupt-Baublock des End. Mit Endstein-Ziegelsteinen und -Mauern gibt es viele dekorative Varianten."},
  {"id":122,"type":"number","question":"Wie viele Feuerbälle schießt ein Blaze in einer Angriffsserie?","answer":3,"unit":"Feuerbälle","tolerance":0,"category":"Mobs","funFact":"Blazes schießen immer 3 Feuerbälle in schneller Folge, pausieren dann kurz. Schneebälle sind die günstigste Gegenmaßnahme."},
  {"id":123,"type":"number","question":"Wie viele verschiedene Banner-Muster (Patterns) gibt es in Minecraft?","answer":42,"unit":"Muster","tolerance":3,"category":"Items","funFact":"Banner können mit Farbstoffen, Blumen und speziellen Mustern dekoriert werden. Shields können Banner aufnehmen."},
  {"id":124,"type":"entity","question":"Welches Item findet man in einer Truhenboot (Chest Boat)?","answer":"Truhe","acceptedAnswers":["Truhe","Chest","Kiste"],"category":"Items","funFact":"Seit 1.19 kann man eine Truhe mit einem Boot kombinieren. Das Truhenboot hat 27 Inventarslots."},
  {"id":125,"type":"number","question":"Wie viele Herzen Absorption gibt ein normaler Goldener Apfel?","answer":4,"unit":"Herzen","tolerance":0,"category":"Items","funFact":"Ein normaler Goldener Apfel gibt Regeneration II (5 Sek.) und Absorption I (2 Min. = 4 extra Herzen)."},
